import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  static final AuthenticationManager _instance = AuthenticationManager._internal();

  factory AuthenticationManager() => _instance;

  AuthenticationManager._internal();

  String? _authToken;
  dynamic _userData;

  Future<void> login(String authToken, Map<String, dynamic> userData) async {
    _authToken = authToken;
    _userData = userData;
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('auth_token', authToken);
    await prefs.setString('user_data', jsonEncode(userData));
  }

  Future<void> logout() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    _authToken = null;
    _userData = null;
    await prefs.remove('auth_token');
    await prefs.remove('user_data');
  }

  Future<bool> isLoggedIn() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    _authToken = prefs.getString('auth_token');
    if (_authToken == null) return false;
    try {
      _userData = jsonDecode(prefs.getString('user_data')!);
      return true;
    } catch (e) {
      logout();
      return false;
    }
  }
}